package com.panini.back.service; import io.jsonwebtoken.*; import io.jsonwebtoken.security.Keys; import org.springframework.beans.factory.annotation.Value; import org.springframework.stereotype.Service; import java.nio.charset.StandardCharsets; import java.time.Instant; import java.util.Date; import javax.crypto.SecretKey; @Service public class JwtService { private final SecretKey key; public JwtService(@Value("${app.jwt.secret}") String secret){ this.key = Keys.hmacShaKeyFor(secret.getBytes(StandardCharsets.UTF_8)); } public String generateToken(String username){ return Jwts.builder().subject(username).issuedAt(Date.from(Instant.now())).expiration(Date.from(Instant.now().plusSeconds(60L*60L*24L*7L))).signWith(key).compact(); } public String extractUsername(String token){ return Jwts.parser().verifyWith(key).build().parseSignedClaims(token).getPayload().getSubject(); } }
